## 2）组件里：兼容解析 + 分片写入避免卡死

把你的 `loadFullLog()` 替换成下面这个版本（保留你原来的参数校验/提示即可）：

```ts
async function yieldToBrowser() {
  // ✅ 让出主线程，避免一次性写入/计算导致卡死
  await new Promise<void>((resolve) => requestAnimationFrame(() => resolve()))
}

function tryParseJSON(text: string) {
  try {
    return JSON.parse(text)
  } catch {
    return null
  }
}

async function setPreTextChunked(text: string) {
  const el = preRef.value
  if (!el) return

  el.textContent = '' // 清空

  // ✅ 分片写入：每片 2000 行（你也可以调整）
  const lines = text.split('\n')
  const chunkSize = 2000

  for (let i = 0; i < lines.length; i += chunkSize) {
    const chunk = lines.slice(i, i + chunkSize).join('\n') + '\n'
    el.appendChild(document.createTextNode(chunk))

    // 每写一片就让出一次，避免长任务卡 UI
    await yieldToBrowser()
  }
}

async function loadFullLog() {
  if (!pipelineName.value) {
    ElMessage.warning('缺少 job_name（pipeline_name），请从列表页带上 query: job_name')
    return
  }
  if (!taskId.value) {
    ElMessage.warning('缺少 task_id（或路由 params.id）')
    return
  }

  loading.value = true
  try {
    const resp = await queryLogs({
      log_type: 'jenkins',
      jenkins: {
        start_at: '0',
        pipeline_name: pipelineName.value,
        task_id: taskId.value,
        is_full: true
      }
    })

    // ✅ 由于 responseType: 'text'，这里拿到的一定是字符串
    const rawText: string = typeof resp?.data === 'string' ? resp.data : String(resp?.data ?? '')

    // 1) 先尝试按 JSON 解析（兼容你原来那种 {code,data:{log:[...]}} 的返回）
    const maybeJson = tryParseJSON(rawText)

    let finalText = ''

    if (maybeJson && typeof maybeJson === 'object') {
      // 兼容：{code, msg, data:{log:[]}} 或 {log:[]}
      if (maybeJson.code !== undefined && maybeJson.code !== 0) {
        ElMessage.error(maybeJson.msg || '获取全量日志失败')
        return
      }
      const logs: string[] =
        Array.isArray(maybeJson?.data?.log) ? maybeJson.data.log :
        Array.isArray(maybeJson?.log) ? maybeJson.log :
        []

      // 有些后端可能返回 data 为字符串
      if (logs.length > 0) finalText = logs.join('\n')
      else if (typeof maybeJson?.data === 'string') finalText = maybeJson.data
      else finalText = rawText // 兜底
    } else {
      // 2) 解析失败：说明就是纯文本日志（你现在 is_full=true 的情况）
      finalText = rawText
    }

    // ✅ 大日志：分片写入，防卡死
    await setPreTextChunked(finalText)

    // ✅ 写完再滚动到底
    await scrollToBottom()
  } catch (e: any) {
    console.error(e)
    ElMessage.error(e?.message || '获取全量日志失败')
  } finally {
    loading.value = false
  }
}
```

